local Config = {}

EntityIconConfig = {}

function EntityIconConfig:init(config)
    for _, v in pairs(config) do
        table.insert(Config, {
            Id = tonumber(v.Id),
            AtlasName = v.AtlasName,
            SpriteName = v.SpriteName,
            Scale = tonumber(v.Scale),
        })
        if isClient then
            TextureAtlasRegister.Instance():addTextureAtlas(v.AtlasName, "")
        end
    end
end

function EntityIconConfig:getConfigById(id)
    for _, config in pairs(Config) do
        if config.Id == tonumber(id) then
            return config
        end
    end
end

